// Declarations for image imports handled by Webpack (asset/resource).
// Webpack returns the file's final URL as a string.
declare module "*.png" {
    const src: string;
    export default src;
}
declare module "*.jpg" {
    const src: string;
    export default src;
}
declare module "*.jpeg" {
    const src: string;
    export default src;
}
declare module "*.gif" {
    const src: string;
    export default src;
}
declare module "*.svg" {
    const src: string;
    export default src;
}
declare module "*.webp" {
    const src: string;
    export default src;
}
